def prime(n):
    if n == 2:
        return True
    if n % 2 == 0 or n <= 1:
        return False
    sqr = int(n**0.5) + 1
    for i in range(3, sqr, 2):
        if n % i == 0:
            return False
    return True


def game(n):
    p = 0
    for i in range(2, n):
        if prime(i) and n % i == 0:
            p = i
            break
    return n-1 + p


n = int(input())
print(game(n))
